class Solution {
public:
    string modifyString(string s) {
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] != '?') {
                continue;
            }
            for (s[i] = 'a'; s[i] <= 'c'; ++s[i]) {
                if ((i == 0 || s[i - 1] != s[i]) && (i == s.size() - 1 || s[i + 1] != s[i])) {
                    break;
                }
            }
        }
        return s;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def modifyString(self, s):
        """
        :type s: str
        :rtype: str
        """
        s = list(s)
        for i in xrange(len(s)):
            if s[i] != '?':
                continue
            for c in ('a', 'b', 'c'):
                if (i == 0 or s[i-1] != c) and (i == len(s)-1 or c != s[i+1]):
                    break
            s[i] = c
        return "".join(s)
